import { useCanvas } from '../hooks/useCanvas.js';
import {
  AreaCanvasInstance,
  AreaCanvasProps,
  ORIENTATION_VERTICAL,
} from '../types/canvas-shape.js';
import { printAreaBuilder } from '../utils/shapes/area-canvas.js';

export function AreaCanvas<Datum>(props: AreaCanvasProps<Datum>) {
  const {
    radius,
    strokeWidth = 2,
    lineStrokeWidth = 2,
    enableDotOverflow = false,
    overlayPadding,
    orientation = ORIENTATION_VERTICAL,
    ...propsAreaCanvas
  }: AreaCanvasProps<Datum> = props;

  // Build how Line canvas should style
  const drawArea = printAreaBuilder<Datum>(
    strokeWidth,
    radius,
    lineStrokeWidth,
    enableDotOverflow,
    overlayPadding,
  );

  // Define draw method for entire Areas shape
  const drawAreaCanvas = (
    ctx: CanvasRenderingContext2D,
    canvas: AreaCanvasInstance<Datum>,
  ) => drawArea(ctx, canvas, canvas.x, canvas.y0, canvas.y1, orientation);

  useCanvas('area', (ctx: CanvasRenderingContext2D) =>
    drawAreaCanvas(ctx, propsAreaCanvas),
  );

  return null;
}
